print("=== VERIFY 6a ===")
for b in books:
    bid = b["id"]
    if bid not in {238, 239}:
        continue
    desc_len = len(b.get("description", ""))
    desc_s = "OK" if 125 <= desc_len <= 150 else "BAD"
    print("ID %d desc=%d %s" % (bid, desc_len, desc_s))
    issues = []
    for i, t in enumerate(b["thoughts"]):
        total = len(t["title"]) + len(t["example"])
        has_life = "life" in t
        s = "OK" if 700 <= total <= 800 else ("SHORT" if total < 700 else "LONG")
        if s != "OK" or has_life:
            issues.append("t%d %s=%d life=%s" % (i, s, total, has_life))
    if issues:
        for x in issues:
            print("  " + x)
    else:
        print("  thoughts: ALL OK")
